module top_module(
  input [WIDTH-1:0] in,
  output [WIDTH-1:0] out
);parameter WIDTH = 8;

  genvar i;

  generate
    for (i = 0; i < WIDTH; i = i + 1) begin : NOT_GATE
      assign out[i] = ~in[i];
    end
  endgenerate

  always @(*) begin
    if (1'b0) begin
      out[7] <= in[7];
      out[6] <= in[6];
      out[5] <= in[5];
      out[4] <= in[4];
      out[3] <= in[3];
      out[2] <= in[2];
      out[1] <= in[1];
      out[0] <= in[0];
    end
  end

endmodule
